import{_ as n,o as t,c as i,ag as r}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"KI-Funktionen","description":"","frontmatter":{},"headers":[],"relativePath":"de/advanced/ai-features.md","filePath":"de/advanced/ai-features.md"}'),a={name:"de/advanced/ai-features.md"};function s(l,e,o,u,h,g){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="ki-funktionen" tabindex="-1">KI-Funktionen <a class="header-anchor" href="#ki-funktionen" aria-label="Permalink to &quot;KI-Funktionen&quot;">​</a></h1><p>MyCompanyDesk enthält KI-gestützte Funktionen, die Ihnen helfen, schneller und intelligenter zu arbeiten.</p><h2 id="kontextbezogener-leitfaden" tabindex="-1">Kontextbezogener Leitfaden <a class="header-anchor" href="#kontextbezogener-leitfaden" aria-label="Permalink to &quot;Kontextbezogener Leitfaden&quot;">​</a></h2><p>Der In-App-Assistent hilft Ihnen bei der Navigation durch MyCompanyDesk:</p><ul><li>Klicken Sie auf das <strong>Hilfe-Symbol</strong> auf einer beliebigen Seite für kontextbezogene Hilfe</li><li>Stellen Sie Fragen zu Funktionen, Workflows oder Einstellungen</li><li>Erhalten Sie Schritt-für-Schritt-Anleitungen für häufige Aufgaben</li><li>Verfügbar in allen vier unterstützten Sprachen</li></ul><p>Der Leitfaden erkennt, auf welcher Seite Sie sich befinden, und liefert relevante Vorschläge.</p><h3 id="chat-limits" tabindex="-1">Chat-Limits <a class="header-anchor" href="#chat-limits" aria-label="Permalink to &quot;Chat-Limits&quot;">​</a></h3><p>Die Chat-Nutzung hängt von Ihrem Tarif ab:</p><table tabindex="0"><thead><tr><th>Tarif</th><th>Chat-Nachrichten</th></tr></thead><tbody><tr><td>Free</td><td>Begrenzt</td></tr><tr><td>Pro</td><td>Großzügiges Kontingent</td></tr><tr><td>Business</td><td>Höchstes Kontingent</td></tr></tbody></table><h2 id="ki-vorschlage" tabindex="-1">KI-Vorschläge <a class="header-anchor" href="#ki-vorschlage" aria-label="Permalink to &quot;KI-Vorschläge&quot;">​</a></h2><p>Intelligente Empfehlungen, die Ihnen helfen, Ihre Datensätze zu kategorisieren und zu beschreiben:</p><h3 id="ausgabenkategorisierung" tabindex="-1">Ausgabenkategorisierung <a class="header-anchor" href="#ausgabenkategorisierung" aria-label="Permalink to &quot;Ausgabenkategorisierung&quot;">​</a></h3><p>Wenn Sie eine Ausgabe erstellen, analysiert die KI die Beschreibung und schlägt die passendste Kategorie vor. Dies spart Zeit und sorgt für konsistente Kategorisierung.</p><h3 id="beschreibungsverbesserungen" tabindex="-1">Beschreibungsverbesserungen <a class="header-anchor" href="#beschreibungsverbesserungen" aria-label="Permalink to &quot;Beschreibungsverbesserungen&quot;">​</a></h3><p>Die KI kann klarere, professionellere Beschreibungen vorschlagen für:</p><ul><li>Rechnungspositionen</li><li>Ausgabenbeschreibungen</li><li>Kundennotizen</li></ul><h3 id="so-funktioniert-es" tabindex="-1">So funktioniert es <a class="header-anchor" href="#so-funktioniert-es" aria-label="Permalink to &quot;So funktioniert es&quot;">​</a></h3><ol><li>Erstellen oder bearbeiten Sie einen Datensatz</li><li>Achten Sie auf den KI-Vorschlagsindikator</li><li>Überprüfen Sie den Vorschlag</li><li>Klicken Sie auf <strong>Übernehmen</strong>, um ihn zu verwenden, oder <strong>Verwerfen</strong>, um ihn zu überspringen</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>KI-Vorschläge erfordern den <strong>Pro</strong>-Tarif oder höher. Aktivieren Sie sie unter <strong>Unternehmen &gt; Funktionen</strong>.</p></div><h2 id="belegscanner" tabindex="-1">Belegscanner <a class="header-anchor" href="#belegscanner" aria-label="Permalink to &quot;Belegscanner&quot;">​</a></h2><p>KI-gestützte OCR extrahiert Daten aus Belegbildern und PDFs:</p><ul><li><strong>Datum</strong> — Wann der Kauf getätigt wurde</li><li><strong>Betrag</strong> — Gesamtkosten</li><li><strong>Lieferant</strong> — An wen Sie gezahlt haben</li><li><strong>Beschreibung</strong> — Was gekauft wurde</li></ul><p>Siehe <a href="/de/advanced/receipt-scanning">Belegscanner</a> für detaillierte Anleitungen.</p><h2 id="textprufung" tabindex="-1">Textprüfung <a class="header-anchor" href="#textprufung" aria-label="Permalink to &quot;Textprüfung&quot;">​</a></h2><p>Grammatik- und Rechtschreibprüfung für Ihre Dokumente:</p><ul><li>Rechnungsbeschreibungen vor dem Versand prüfen</li><li>Angebotsinhalt verifizieren</li><li>Tippfehler in kundenseitigen Texten korrigieren</li></ul><p>Unterstützt Englisch, Niederländisch, Deutsch und Französisch.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Textprüfung erfordert den <strong>Pro</strong>-Tarif oder höher.</p></div><h2 id="kontozusammenfassungen" tabindex="-1">Kontozusammenfassungen <a class="header-anchor" href="#kontozusammenfassungen" aria-label="Permalink to &quot;Kontozusammenfassungen&quot;">​</a></h2><p>Die KI erstellt regelmäßige Zusammenfassungen Ihrer Geschäftsaktivitäten:</p><ul><li><strong>Täglich</strong> — Kurzer Überblick über die Tagesgeschäfte</li><li><strong>Wöchentlich</strong> — Wochenrückblick mit Trends</li><li><strong>Monatlich</strong> — Umfassende monatliche Analyse</li></ul><p>Zusammenfassungen werden in Ihrer bevorzugten Sprache erstellt und sind über das Dashboard verfügbar.</p><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Aktivieren Sie KI-Vorschläge einmal und sie arbeiten automatisch im Hintergrund</li><li>Belegscanner ist besonders nützlich für Papierbelege — machen Sie einfach ein Foto</li><li>Der kontextbezogene Leitfaden kann die meisten „Wie mache ich...&quot;-Fragen zur App beantworten</li><li>KI-Funktionen nutzen datenschutzfreundliche Verarbeitung — Ihre Daten bleiben sicher</li></ul>',34)])])}const b=n(a,[["render",s]]);export{c as __pageData,b as default};
